#include <stdio.h>

int main() {
  int number = 42;
  int *ptr = &number;
  printf("Number's value: %d\n", number);
  printf("Number's address: %p\n", (void *)ptr);
  printf("Value at address: %d\n", *ptr);
  return 0;
}
// Output:
// Number's value: 42
// Number's address: (yaddaş ünvanı, məsələn, 0x7ffee4b0a4ac)
// Value at address: 42

#include <stdio.h>

int main() {
  int value = 10;
  int *ptr = &value;
  printf("Original value: %d\n", value);
  *ptr = 20;
  printf("Modified value: %d\n", value);
  return 0;
}
// Output:
// Original value: 10
// Modified value: 20

#include <stdio.h>

int main() {
  int numbers[4] = {10, 20, 30, 40};
  int *ptr = numbers;
  for (int i = 0; i < 4; i++) {
    printf("Element %d: %d\n", i, *(ptr + i));
  }
  return 0;
}
// Output:
// Element 0: 10
// Element 1: 20
// Element 2: 30
// Element 3: 40

#include <stdio.h>

void swap(int *a, int *b) {
  int temp = *a;
  *a = *b;
  *b = temp;
}

int main() {
  int x = 5, y = 10;
  printf("Before swap: x = %d, y = %d\n", x, y);
  swap(&x, &y);
  printf("After swap: x = %d, y = %d\n", x, y);
  return 0;
}
// Output:
// Before swap: x = 5, y = 10
// After swap: x = 10, y = 5

